import React, { useState, useEffect } from 'react';
import { db } from '../../utils/firebase'; 
import { collection, addDoc, onSnapshot, query, deleteDoc, doc, getDoc, collectionGroup, orderBy } from 'firebase/firestore';

export default function MaterialDept() {
  // Auth Gates Structure
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);
  const [adminLoginId, setAdminLoginId] = useState('');
  const [adminPassword, setAdminPassword] = useState('');

  // Operational Control States
  const [currentVendorId, setCurrentVendorId] = useState('platform no 1'); 
  const [workerName, setWorkerName] = useState('');
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [workersList, setWorkersList] = useState([]);
  const [globalActivityLogs, setGlobalActivityLogs] = useState([]); // Global Work Feed State
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [activeLightbox, setActiveLightbox] = useState(null); // Full Screen Image Viewer

  // 1. Live Stream workers based on specific selected Platform Node
  useEffect(() => {
    if (!isAdminLoggedIn || !currentVendorId.trim()) return;

    const q = query(collection(db, "vendors", currentVendorId.trim(), "workers"));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const workers = [];
      snapshot.forEach((doc) => {
        workers.push({ id: doc.id, ...doc.data() });
      });
      setWorkersList(workers);
    }, (err) => {
      console.error("Snapshot error:", err);
    });
    
    return () => unsubscribe();
  }, [currentVendorId, isAdminLoggedIn]);

  // 2. 🔥 REVOLUTIONARY FIX: Global Real-time Work Logs Feed (Bypasses nested platform spelling bugs)
  useEffect(() => {
    if (!isAdminLoggedIn) return;

    // collectionGroup se pure project ki 'transactions' ya 'logs' collections se image uploads trace honge
    const logsQuery = query(collectionGroup(db, 'transactions'), orderBy('createdAt', 'desc'));
    
    const unsubscribe = onSnapshot(logsQuery, (snapshot) => {
      const logs = [];
      snapshot.forEach((doc) => {
        logs.push({ id: doc.id, ...doc.data() });
      });
      setGlobalActivityLogs(logs);
    }, (error) => {
      // Fallback agar ordering index immediate ready nahi hai database par
      const fallbackQuery = query(collectionGroup(db, 'transactions'));
      onSnapshot(fallbackQuery, (snapshot) => {
        const logs = [];
        snapshot.forEach((doc) => { logs.push({ id: doc.id, ...doc.data() }); });
        setGlobalActivityLogs(logs.sort((a,b) => b.createdAt - a.createdAt));
      });
    });

    return () => unsubscribe();
  }, [isAdminLoggedIn]);

  // Auth Handler Verification Function
  const handleAdminAuthCheck = async (e) => {
    e.preventDefault();
    if (!adminLoginId.trim() || !adminPassword) return alert("Fill entry fields.");
    
    try {
      const cleanId = adminLoginId.trim();

      const adminDocRef = doc(db, "admins", cleanId);
      const adminRes = await getDoc(adminDocRef);

      if (adminRes.exists() && adminRes.data().password === adminPassword) {
        setIsAdminLoggedIn(true);
        return;
      }

      const vendorDocRef = doc(db, "vendors", cleanId);
      const vendorRes = await getDoc(vendorDocRef);

      if (vendorRes.exists() && vendorRes.data().password === adminPassword) {
        setCurrentVendorId(cleanId); 
        setIsAdminLoggedIn(true);
        return;
      }

      alert("Invalid credential parameters. Na admin mila na vendor!");
    } catch (err) {
      console.error(err);
      alert("Error checking backend cluster authorization entries.");
    }
  };

  const handleAddWorker = async (e) => {
    e.preventDefault();
    if (!workerName || !loginId || !password) return alert("Fill all operational credentials!");
    
    setIsSubmitting(true);
    try {
      const workerSubRef = collection(db, "vendors", currentVendorId.trim(), "workers");
      await addDoc(workerSubRef, {
        name: workerName.trim(),
        loginId: loginId.trim().toLowerCase(),
        password: password.trim(),
        role: "storage_worker",
        mappedPlatform: currentVendorId.trim(),
        createdAt: new Date()
      });

      setWorkerName(''); setLoginId(''); setPassword('');
      alert(`Worker registered successfully under ${currentVendorId}!`);
    } catch (err) {
      console.error(err);
      alert("Firestore Node Error during deployment logging.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteWorker = async (id) => {
    if (window.confirm("Are you sure you want to terminate this staff registry?")) {
      try {
        await deleteDoc(doc(db, "vendors", currentVendorId.trim(), "workers", id));
      } catch (err) {
        alert("Operation failed.");
      }
    }
  };

  /* ── 🛡️ BLOCKER 1: AUTH GATE SCREEN ── */
  if (!isAdminLoggedIn) {
    return (
      <div style={{ display: 'flex', height: '100vh', alignItems: 'center', justifyContent: 'center', background: '#0A1628', fontFamily: 'system-ui' }}>
        <form onSubmit={handleAdminAuthCheck} style={{ background: '#fff', padding: '32px 28px', borderRadius: 16, width: 340, boxShadow: '0 8px 30px rgba(0,0,0,0.3)' }}>
          <div style={{ fontSize: 20, fontWeight: 800, color: '#0A1628', marginBottom: 6, textAlign: 'center' }}>Material Storage Dept</div>
          <div style={{ fontSize: 13, color: '#546E7A', marginBottom: 24, textAlign: 'center', fontWeight: 500 }}>Admin Node Authentication Gate</div>
          
          <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#3D4F61', marginBottom: 5 }}>ADMIN CONTROL ID</label>
          <input type="text" value={adminLoginId} onChange={e => setAdminLoginId(e.target.value)} placeholder="e.g. admin_ngp" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #DDE3E9', marginBottom: 14, boxSizing: 'border-box', fontSize: 13 }} />
          
          <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#3D4F61', marginBottom: 5 }}>SECURE ACCESS PIN</label>
          <input type="password" value={adminPassword} onChange={e => setAdminPassword(e.target.value)} placeholder="••••••••" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #DDE3E9', marginBottom: 20, boxSizing: 'border-box', fontSize: 13 }} />
          
          <button type="submit" style={{ width: '100%', padding: 11, background: '#10B981', color: '#fff', border: 'none', borderRadius: 8, fontWeight: 700, fontSize: 13, cursor: 'pointer' }}>Verify & Unlock Panel</button>
        </form>
      </div>
    );
  }

  /* ── 🔓 BLOCKER 2: MAIN PANEL CONSOLE ── */
  return (
    <div style={{ padding: '30px', background: '#F8FAFC', minHeight: '100vh', fontFamily: 'system-ui' }}>
      
      {/* Lightbox Modal Component */}
      {activeLightbox && (
        <div onClick={() => setActiveLightbox(null)} style={{ position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh', background: 'rgba(15,23,42,0.9)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', backdropFilter: 'blur(4px)', cursor: 'zoom-out' }}>
          <img src={activeLightbox} alt="Proof Blueprint Asset" style={{ maxWidth: '90%', maxHeight: '85vh', borderRadius: '12px', border: '3px solid #fff' }} />
        </div>
      )}

      <div style={{ marginBottom: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <h2 style={{ fontSize: '24px', fontWeight: 800, color: '#0F172A', margin: 0 }}>Material Storage Staff Management (CRUD)</h2>
          <p style={{ fontSize: '13px', color: '#64748B', margin: '4px 0 0 0' }}>Admin Dashboard: Configure active station nodes and deploy handling staff credentials</p>
        </div>
        <button onClick={() => setIsAdminLoggedIn(false)} style={{ background: '#EF4444', color: '#fff', border: 'none', padding: '8px 16px', borderRadius: '6px', fontSize: '12px', fontWeight: '700', cursor: 'pointer' }}>
          🔒 Lock Console
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', alignItems: 'start' }}>
        
        {/* LEFT COLUMN: STAFF REGISTRY CONTROL AND CRUD FORM */}
        <div>
          <div style={{ background: '#EFF6FF', border: '1px solid #BFDBFE', padding: '16px', borderRadius: '12px', marginBottom: '20px' }}>
            <label style={{ display: 'block', fontSize: '12px', fontWeight: 700, color: '#1E40AF', marginBottom: '6px' }}>TARGET PLATFORM CONFIGURATION LOCK (ADMIN INPUT)</label>
            <input 
              type="text" 
              value={currentVendorId} 
              onChange={e => setCurrentVendorId(e.target.value)} 
              placeholder="e.g. platform no 1" 
              style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #93C5FD', fontWeight: 600, color: '#1E3A8A', boxSizing: 'border-box' }} 
            />
          </div>

          <form onSubmit={handleAddWorker} style={{ background: '#fff', padding: '20px', borderRadius: '12px', border: '1px solid #E2E8F0', marginBottom: '24px' }}>
            <h3 style={{ margin: '0 0 14px 0', fontSize: '14px', fontWeight: '700' }}>Add New Personnel Node</h3>
            <div style={{ marginBottom: 12 }}>
              <label style={{ display: 'block', fontSize: '11px', fontWeight: 700, color: '#475569', marginBottom: '4px' }}>WORKER / OPERATOR NAME</label>
              <input type="text" value={workerName} onChange={e => setWorkerName(e.target.value)} placeholder="e.g. Ramesh Kumar" style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #CBD5E1', boxSizing: 'border-box' }} required />
            </div>
            <div style={{ marginBottom: 12 }}>
              <label style={{ display: 'block', fontSize: '11px', fontWeight: 700, color: '#475569', marginBottom: '4px' }}>PHONE / LOGIN ID</label>
              <input type="text" value={loginId} onChange={e => setLoginId(e.target.value)} placeholder="username" style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #CBD5E1', boxSizing: 'border-box' }} required />
            </div>
            <div style={{ marginBottom: 16 }}>
              <label style={{ display: 'block', fontSize: '11px', fontWeight: 700, color: '#475569', marginBottom: '4px' }}>LOGIN PASSWORD</label>
              <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••" style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #CBD5E1', boxSizing: 'border-box' }} required />
            </div>
            <button type="submit" disabled={isSubmitting} style={{ width: '100%', background: '#10B981', color: '#fff', border: 'none', padding: '11px', borderRadius: '6px', fontWeight: 700, cursor: 'pointer' }}>
              {isSubmitting ? "Saving Parameters..." : "+ Deploy Worker Profile"}
            </button>
          </form>

          {/* Active Staff Registry Card */}
          <div style={{ background: '#fff', borderRadius: '12px', border: '1px solid #E2E8F0', padding: '16px' }}>
            <h3 style={{ fontSize: '14px', fontWeight: 700, color: '#334155', margin: '0 0 12px 0' }}>Active Operators Registry at [{currentVendorId}]</h3>
            {workersList.map((worker) => (
              <div key={worker.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px', borderBottom: '1px solid #F1F5F9' }}>
                <div>
                  <div style={{ fontWeight: 700, color: '#1E293B' }}>📦 {worker.name}</div>
                  <div style={{ fontSize: '12px', color: '#64748B', marginTop: '3px' }}>
                    ID: <span style={{ color: '#0F172A', fontWeight: 600 }}>{worker.loginId}</span> | Pin: <span style={{ color: '#0F172A' }}>{worker.password}</span>
                  </div>
                </div>
                <button type="button" onClick={() => handleDeleteWorker(worker.id)} style={{ background: 'transparent', border: 'none', color: '#EF4444', cursor: 'pointer', fontSize: '16px' }}>🗑️</button>
              </div>
            ))}
            {workersList.length === 0 && <p style={{ textAlign: 'center', color: '#94A3B8', fontSize: '13px', margin: '20px 0' }}>No personnel mapped to this specific terminal point.</p>}
          </div>
        </div>

        {/* RIGHT COLUMN: 🔥 REAL-TIME GLOBAL WORKER TRANSACTIONS & IMAGE FEED */}
        <div style={{ background: '#fff', borderRadius: '12px', border: '1px solid #E2E8F0', padding: '20px', minHeight: '500px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px', borderBottom: '2px solid #F1F5F9', paddingBottom: '10px' }}>
            <div>
              <h3 style={{ fontSize: '16px', fontWeight: 800, color: '#0F172A', margin: 0 }}>🔴 Live Workers Activity Feed</h3>
              <p style={{ fontSize: '11px', color: '#64748B', margin: '2px 0 0 0' }}>Real-time verification channel for image asset streaming uploads</p>
            </div>
            <span style={{ background: '#D1FAE5', color: '#065F46', fontSize: '11px', fontWeight: 700, padding: '4px 8px', borderRadius: '99px' }}>
              {globalActivityLogs.length} Actions Tracked
            </span>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', maxHeight: '60vh', overflowY: 'auto', paddingRight: '4px' }}>
            {globalActivityLogs.map((log) => {
              const imageAsset = log.proofImageUrl || log.imageUrl || log.cleanerPhoto;
              return (
                <div key={log.id} style={{ border: '1px solid #E2E8F0', borderRadius: '10px', padding: '12px', background: '#F8FAFC', display: 'flex', gap: '14px', alignItems: 'center' }}>
                  
                  {/* Left Side: Thumbnail Preview */}
                  <div 
                    onClick={() => { if(imageAsset) setActiveLightbox(imageAsset); }}
                    style={{ 
                      width: '75px', height: '75px', borderRadius: '8px', 
                      background: imageAsset ? `url(${imageAsset}) center/cover no-repeat` : '#1E293B',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      cursor: imageAsset ? 'zoom-in' : 'default', border: '1px solid #CBD5E1', flexShrink: 0
                    }}
                  >
                    {!imageAsset && <span style={{ color: '#94A3B8', fontSize: '9px', textAlign: 'center', fontWeight: 600 }}>No Image<br/>Asset</span>}
                  </div>

                  {/* Right Side: Data Variables */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <span style={{ fontWeight: '700', fontSize: '13px', color: '#0F172A' }}>{log.workerName || log.name || 'Unknown Operator'}</span>
                      <span style={{ fontSize: '10px', color: '#94A3B8' }}>
                        {log.createdAt?.seconds ? new Date(log.createdAt.seconds * 1000).toLocaleTimeString() : 'Live'}
                      </span>
                    </div>

                    <div style={{ fontSize: '11.5px', color: '#475569', marginTop: '4px' }}>
                      Action: <strong style={{ color: log.type === 'WITHDRAW' ? '#EF4444' : '#10B981' }}>{log.type || 'STOCK OPERATION'}</strong>
                    </div>

                    <div style={{ display: 'flex', gap: '6px', marginTop: '6px', flexWrap: 'wrap' }}>
                      <span style={{ fontSize: '10px', background: '#DBEAFE', color: '#1E40AF', padding: '2px 6px', borderRadius: '4px', fontWeight: 600 }}>
                        📍 {String(log.mappedPlatform || log.platform || 'General Terminal').toUpperCase()}
                      </span>
                      {imageAsset && (
                        <span style={{ fontSize: '10px', background: '#D1FAE5', color: '#065F46', padding: '2px 6px', borderRadius: '4px', fontWeight: 700 }}>
                          📸 Image Attached
                        </span>
                      )}
                    </div>
                  </div>

                </div>
              );
            })}

            {globalActivityLogs.length === 0 && (
              <div style={{ textAlign: 'center', padding: '40px 20px', color: '#94A3B8' }}>
                <div style={{ fontSize: '24px' }}>📡</div>
                <p style={{ fontSize: '13px', margin: '8px 0 0 0' }}>Awaiting active pipeline transmissions from worker device cameras...</p>
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
}
